import{A as n}from"./chunks/theme.BnJirLdI.js";import{u as l}from"./chunks/link-icons.fvmyrjZg.js";import{c as r}from"./chunks/encryption.S1_HwLux.js";import{_ as i}from"./chunks/CanvasViewer.vue_vue_type_script_setup_true_lang.BaEQOOyt.js";import{a3 as a,o as s,c as d,ah as e,v as o,s as g}from"./chunks/framework.cbxun9lb.js";import"./chunks/index.Difenjld.js";const _=JSON.parse('{"title":"Obsidian WebDAV Sync","titleTemplate":"Obsidian 的 WebDAV 同步插件","description":"WebDAV Sync 是一款用于 Obsidian 的插件，可将你的仓库与 WebDAV 服务器同步。它在可靠的双向同步、更优的性能以及摆脱厂商锁定方面优于现有解决方案。","frontmatter":{"layout":"project","title":"Obsidian WebDAV Sync","titleTemplate":"Obsidian 的 WebDAV 同步插件","description":"WebDAV Sync 是一款用于 Obsidian 的插件，可将你的仓库与 WebDAV 服务器同步。它在可靠的双向同步、更优的性能以及摆脱厂商锁定方面优于现有解决方案。","logo":"https://github.com/hesprs/obsidian-webdav-sync/raw/main/assets/logo.svg","links":[{"name":"GitHub 仓库","url":"https://github.com/hesprs/obsidian-webdav-sync","color":"#010409"}],"head":[["meta",{"name":"keywords","content":"Obsidian, Obsidian 插件, Obsidian WebDAV Sync, Obsidian WebDAV, WebDAV 同步, 跨设备同步"}]]},"headers":[],"relativePath":"zh-Hans/projects/obsidian-webdav-sync.md","filePath":"zh-Hans/projects/obsidian-webdav-sync.md","lastUpdated":1777982901000}'),c={name:"zh-Hans/projects/obsidian-webdav-sync.md"},V=a({...c,setup(b){return l({"GitHub 仓库":n}),(h,t)=>(s(),d("div",null,[t[0]||(t[0]=e('<h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h2><p>Obsidian WebDAV Sync 是一款通用的双向 WebDAV 同步插件，专为 Obsidian 设计。它的诞生源于当前缺乏能够可靠且便捷地将仓库与 WebDAV 服务器同步的插件。它在可靠的双向同步、更优的性能以及摆脱厂商锁定方面优于现有解决方案：</p><p>🔄 <strong>可靠的双向同步</strong>：</p><ul><li>本插件将你的仓库与 WebDAV 存储进行同步。</li><li>它执行三方比较：远程状态、本地状态，以及上次同步时记录的本地和远程状态。</li><li>随后遵循决策矩阵以实现最高精度和数据完整性，详见<a href="#技术解析">下文</a>。</li></ul><p>🔀 <strong>自动同步与冲突处理</strong>：</p><ul><li>插件支持以下自动触发的同步方式： <ul><li><strong>启动同步</strong>：当 Obsidian 启动时触发同步。</li><li><strong>定时同步</strong>：周期性触发同步。</li><li><strong>实时同步</strong>：检测到更改时立即触发同步。</li></ul></li><li>插件支持以下冲突处理方法： <ul><li>智能合并</li><li>最新者胜出</li><li>使用远程版本</li><li>使用本地版本</li><li>跳过</li></ul></li></ul><p>🔐 客户端加密：</p><ul><li>本插件支持在上传前对文件进行加密。</li><li>它能防止未经授权的文件访问，并检测远程端意外的文件修改和移动。</li><li>该加密流程基于更严格的威胁模型，相比类似解决方案（如 Remotely Save），实现了<strong>理论上更高的安全性、更快的性能和更小的插件体积</strong>，详见<a href="https://github.com/hesprs/obsidian-webdav-sync/blob/main/docs/encryption.md" target="_blank" rel="noreferrer">加密规范</a>。</li></ul><p>⚡ <strong>极致性能</strong>：</p><ul><li>大多数同步操作通过并行网络请求执行。</li><li>实时同步默认使用缓存的远程状态，使其能在数秒内完成同步。</li><li>体积比 Remotely Save <strong>小 10 倍</strong>，启动加载时间<strong>快 8 倍</strong>。</li></ul><p>🧰 <strong>详细配置</strong>：</p><ul><li>插件允许用户调整各种参数以适应不同的服务： <ul><li><strong>最大并发 WebDAV 请求数</strong>：应对服务速率限制。</li><li><strong>WebDAV 请求最小间隔时间</strong>：应对服务速率限制。</li><li><strong>跳过大文件</strong>：应对存储空间不足的情况。</li><li><strong>最大并发同步任务数</strong>：控制 CPU 和磁盘占用。</li><li><strong>最大并发吞吐量</strong>：控制内存使用并防止崩溃。</li></ul></li></ul><p>📦 <strong>生产级可扩展性</strong>：</p><ul><li>流畅处理包含超过 3000 个文件的仓库。</li><li>负载均衡和下载分块功能使插件能够一次性处理千兆字节级的数据。</li><li>大文件下载支持断点续传。</li></ul><p>🎨 <strong>优秀的用户界面与可观测性</strong>：</p><ul><li>提供四种方式（模态框、状态栏、通知、日志）让你随时了解同步进度。</li><li>文件更改以文件树形式呈现，支持细粒度的选择性同步。</li><li>日志工具输出人类可读的 Markdown 文档。</li></ul><h2 id="又是另一个同步插件" tabindex="-1">又是另一个同步插件？ <a class="header-anchor" href="#又是另一个同步插件" aria-label="Permalink to “又是另一个同步插件？”">​</a></h2><p>作为一名在多设备间工作的 Obsidian 用户，我亲身经历过同步困境：寻找一个既可靠、灵活，又不损害数据完整性的解决方案。在尝试了社区中几乎所有的同步插件后，我发现它们各自都存在令我日常工作流程受挫的权衡：</p><ul><li><strong>Remotely Save</strong>：功能全面，但存在维护停滞和 Bug 问题——例如已删除的文件会神秘重现（这正是我弃用它的主要原因）。</li><li><strong>Syncthing Integration</strong>：提供了优秀的 P2P 同步体验，但要求所有设备必须同时在线。</li><li><strong>Live Sync</strong>：虽然稳健，但代价是复杂的服务器搭建流程。</li><li><strong>基于 Git 的方案</strong>：在版本控制方面表现出色，但并不适合无缝的日常同步。</li></ul><p>随后我发现了 <a href="https://github.com/nutstore/obsidian-nutstore-sync" target="_blank" rel="noreferrer">Nutstore Sync</a> —— 一款优秀的插件，但仅适用于坚果云。我想：为什么不把它做成通用的呢？于是我对其进行了 fork，并进行了大规模重构，以消除厂商锁定、提升性能并增强稳定性。由此诞生的作品便是 <strong>Obsidian WebDAV Sync</strong>。</p><h2 id="技术解析" tabindex="-1">技术解析 <a class="header-anchor" href="#技术解析" aria-label="Permalink to “技术解析”">​</a></h2><h3 id="文件处理" tabindex="-1">文件处理 <a class="header-anchor" href="#文件处理" aria-label="Permalink to “文件处理”">​</a></h3><p>将 Obsidian 仓库同步到 WebDAV 服务器是一个典型的<strong>分布式协调</strong>问题，其中每个客户端都拥有自己的仓库副本和更改记录，且中间没有集中的解析器。目标是在客户端之间同步仓库，以实现最大的数据完整性。</p><p>为解决这一问题，本插件保留了本地和远程文件上次已知同步状态的记录。在同步期间，它会评估每个文件路径的<strong>三种状态（当前本地、当前远程、上次同步时记录的本地和远程）</strong>，并据此决定同步操作：</p><blockquote><p>✅ = 存在，❌ = 不存在，✏️ = 相较于记录已更改</p></blockquote><table tabindex="0"><thead><tr><th>情况</th><th style="text-align:center;">本地文件</th><th style="text-align:center;">远程文件</th><th style="text-align:center;">同步记录</th><th>操作</th></tr></thead><tbody><tr><td>1</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>⏭️ <strong>跳过</strong>（已同步）</td></tr><tr><td>2</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⚠️ <strong>解决冲突</strong>（应用策略）</td></tr><tr><td>3</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⬇️ <strong>拉取</strong>（下载远程版本）</td></tr><tr><td>4</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>⬆️ <strong>推送</strong>（上传本地版本）</td></tr><tr><td>5</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>🗑️ <strong>删除本地</strong>（清理）</td></tr><tr><td>6</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>🗑️ <strong>删除远程</strong>（清理）</td></tr><tr><td>7</td><td style="text-align:center;">❌</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⬇️ <strong>拉取</strong>（从远程恢复）</td></tr><tr><td>8</td><td style="text-align:center;">✏️</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>⬆️ <strong>推送</strong>（恢复到远程）</td></tr><tr><td>9</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅（与本地比较）</td><td style="text-align:center;">❌</td><td>📝 <strong>记录</strong>（捕获未记录的文件）</td></tr><tr><td>10</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️（与本地比较）</td><td style="text-align:center;">❌</td><td>⚠️ <strong>解决冲突</strong>（首次同步）</td></tr><tr><td>11</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td>⬇️ <strong>拉取</strong>（新远程文件）</td></tr><tr><td>12</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td>⬆️ <strong>推送</strong>（新本地文件）</td></tr><tr><td>13</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>🧹 <strong>清理记录</strong>（数据库清理）</td></tr></tbody></table><h3 id="加密" tabindex="-1">加密 <a class="header-anchor" href="#加密" aria-label="Permalink to “加密”">​</a></h3><p>客户端加密是本插件中<strong>设计最严谨</strong>的部分。加密并非简单地使用密钥对文件的一部分进行编码，那种方式可能在几分钟内被攻击者破解。WebDAV Sync 中的真实加密过程涉及<strong>多层混淆和扩散</strong>，如下图所示。</p>',28)),o(i,{canvas:g(r)},null,8,["canvas"]),t[1]||(t[1]=e('<p>在盐值中使用 WebDAV 服务器信息来混合用户密码，避免了 Rclone 式通用固定盐值带来的风险。通过选择 <code>AES-GCM-SIV-256</code> 作为文件路径加密的确定性算法，并将文件路径和大小直接编织到文件加密密钥中，该算法能够最大限度地验证下载文件的完整性，并检测恶意的文件移动和截断。</p><p>由此产生的加密流程在<strong>理论上比类似解决方案（如 Rclone Crypt）和竞争插件（如底层使用 Crypt 的 Remotely Save）更安全、更快，且更符合 Obsidian 原生体验</strong>。</p><h3 id="更多细节" tabindex="-1">更多细节 <a class="header-anchor" href="#更多细节" aria-label="Permalink to “更多细节”">​</a></h3><p>本插件的技术层面还有更多值得深入探讨之处。</p><p>例如，在同步前比较四种状态意味着我们需要在每次同步开始时进行<strong>完整的 WebDAV、本地仓库和记录遍历</strong>，这对于大型仓库来说是不切实际的。为解决这一问题，引入了<strong>快速模式</strong>，它复用记录中的远程状态作为当前状态，从而避免每次同步都遍历整个 WebDAV。快速模式默认用于实时同步，建议在快速模式同步之前进行一次常规同步（由手动、周期性或启动触发）。</p><p>此外，存储所有文件的记录和内容（以比较并决定文件是否更改）需要大量且活跃的存储空间以确保保真度。本插件利用 IndexedDB 来存储记录并按需查询。</p><p>另外，为了控制内存使用并防止在下载大文件时崩溃，本插件采用了专门的<strong>负载均衡和下载分块</strong>机制。当文件大小超过用户配置的阈值时，插件会将文件分割成块并并行下载，且在每个块完成后立即保存到本地缓存。在最后阶段，插件对缓存进行排序并增量写入完整文件。这不仅确保在处理 GB 级文件时内存消耗保持在恒定的低水平，还使大文件下载完全支持断点续传。</p><h2 id="安装与设置" tabindex="-1">安装与设置 <a class="header-anchor" href="#安装与设置" aria-label="Permalink to “安装与设置”">​</a></h2><p>由于插件目前处于测试阶段，安装需要 <strong>BRAT</strong>（Beta Reviewer Auto-update Tool）插件：</p><h3 id="第一步-安装-brat" tabindex="-1">第一步：安装 BRAT <a class="header-anchor" href="#第一步-安装-brat" aria-label="Permalink to “第一步：安装 BRAT”">​</a></h3><ol><li>打开 Obsidian 设置 → 社区插件</li><li>搜索并安装 <strong>BRAT</strong></li><li>启用该插件</li></ol><h3 id="第二步-添加-obsidian-webdav-sync" tabindex="-1">第二步：添加 Obsidian WebDAV Sync <a class="header-anchor" href="#第二步-添加-obsidian-webdav-sync" aria-label="Permalink to “第二步：添加 Obsidian WebDAV Sync”">​</a></h3><ol><li>打开 BRAT 设置</li><li>点击 <strong>添加测试版插件</strong></li><li>粘贴仓库 URL：<code>https://github.com/hesprs/obsidian-webdav-sync</code></li><li>选择最新版本并点击 <strong>添加插件</strong></li></ol><h3 id="第三步-配置-webdav-连接" tabindex="-1">第三步：配置 WebDAV 连接 <a class="header-anchor" href="#第三步-配置-webdav-连接" aria-label="Permalink to “第三步：配置 WebDAV 连接”">​</a></h3><ol><li>输入你的 WebDAV 服务器 URL</li><li>提供账户凭据</li><li>点击 <strong>检查连接</strong> 以验证</li><li>选择你的远程目录</li><li>发起首次同步</li></ol><blockquote><p>在首次同步前，请务必备份重要笔记。虽然本插件能稳健地处理文件存在性解析，但在初次设置时拥有备份能让你更安心。</p></blockquote><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to “许可证”">​</a></h2><p>Obsidian WebDAV Sync 采用 <a href="https://www.gnu.org/licenses/agpl-3.0.en.html" target="_blank" rel="noreferrer">AGPL-3.0 许可证</a>。</p>',18))]))}});export{_ as __pageData,V as default};
